        ) or (
          "inbox_v2_client_merge_graph_heads"."revision" >= 1
          and "inbox_v2_client_merge_graph_heads"."updated_at" is not null
          and isfinite("inbox_v2_client_merge_graph_heads"."updated_at")
          and "inbox_v2_client_merge_graph_heads"."latest_redirect_id" is not null
        ))
);
