CREATE TABLE "inbox_v2_client_merge_node_states" (
	"tenant_id" text NOT NULL,
	"client_id" text NOT NULL,
	"state" "inbox_v2_client_merge_node_state_kind" NOT NULL,
	"next_client_id" text,
	"redirect_id" text,
	"maximum_inbound_depth" integer DEFAULT 0 NOT NULL,
	"revision" bigint DEFAULT 1 NOT NULL,
	"last_graph_revision" bigint,
	"updated_at" timestamp (3) with time zone NOT NULL,
	CONSTRAINT "inbox_v2_client_merge_node_states_pk" PRIMARY KEY("tenant_id","client_id"),
	CONSTRAINT "inbox_v2_client_merge_node_states_shape_check" CHECK ((
          "inbox_v2_client_merge_node_states"."state" = 'canonical_root'
          and "inbox_v2_client_merge_node_states"."next_client_id" is null
          and "inbox_v2_client_merge_node_states"."redirect_id" is null
        ) or (
          "inbox_v2_client_merge_node_states"."state" = 'redirected'
          and "inbox_v2_client_merge_node_states"."next_client_id" is not null
          and "inbox_v2_client_merge_node_states"."next_client_id" <> "inbox_v2_client_merge_node_states"."client_id"
          and "inbox_v2_client_merge_node_states"."redirect_id" is not null
          and "inbox_v2_client_merge_node_states"."maximum_inbound_depth" < 64
        )),
	CONSTRAINT "inbox_v2_client_merge_node_states_initial_or_mutated_check" CHECK ((
          "inbox_v2_client_merge_node_states"."last_graph_revision" is null
          and "inbox_v2_client_merge_node_states"."state" = 'canonical_root'
          and "inbox_v2_client_merge_node_states"."maximum_inbound_depth" = 0
          and "inbox_v2_client_merge_node_states"."revision" = 1
        ) or (
          "inbox_v2_client_merge_node_states"."last_graph_revision" is not null
          and "inbox_v2_client_merge_node_states"."last_graph_revision" >= 1
          and "inbox_v2_client_merge_node_states"."revision" >= 2
          and (
            "inbox_v2_client_merge_node_states"."state" = 'redirected'
            or "inbox_v2_client_merge_node_states"."maximum_inbound_depth" between 1 and 64
          )
        )),
	CONSTRAINT "inbox_v2_client_merge_node_states_depth_revision_check" CHECK ("inbox_v2_client_merge_node_states"."maximum_inbound_depth" between 0 and 64
        and "inbox_v2_client_merge_node_states"."revision" >= 1
        and isfinite("inbox_v2_client_merge_node_states"."updated_at"))
);
