	"revision" bigint DEFAULT 1 NOT NULL,
	CONSTRAINT "inbox_v2_client_merge_redirects_pk" PRIMARY KEY("tenant_id","id"),
	CONSTRAINT "inbox_v2_client_merge_redirects_graph_revision_unique" UNIQUE("tenant_id","resulting_graph_revision"),
	CONSTRAINT "inbox_v2_client_merge_redirects_source_root_unique" UNIQUE("tenant_id","source_root_client_id"),
	CONSTRAINT "inbox_v2_client_merge_redirects_id_format_check" CHECK (char_length("inbox_v2_client_merge_redirects"."id") <= 256
        and "inbox_v2_client_merge_redirects"."id" ~ '^client_merge_redirect:[A-Za-z0-9][A-Za-z0-9._~:-]{0,199}$'),
	CONSTRAINT "inbox_v2_client_merge_redirects_distinct_roots_check" CHECK ("inbox_v2_client_merge_redirects"."source_root_client_id" <> "inbox_v2_client_merge_redirects"."target_root_client_id"),
	CONSTRAINT "inbox_v2_client_merge_redirects_actor_xor_check" CHECK ((
          "inbox_v2_client_merge_redirects"."decision_actor_kind" = 'employee'
          and "inbox_v2_client_merge_redirects"."decision_actor_employee_id" is not null
          and "inbox_v2_client_merge_redirects"."decision_actor_trusted_service_id" is null
        ) or (
          "inbox_v2_client_merge_redirects"."decision_actor_kind" in ('trusted_service', 'migration_service')
          and "inbox_v2_client_merge_redirects"."decision_actor_employee_id" is null
          and "inbox_v2_client_merge_redirects"."decision_actor_trusted_service_id" is not null
