	"alias_realm_id" text NOT NULL,
	"alias_realm_version" text NOT NULL,
	"alias_canonicalization_version" text NOT NULL,
	"alias_scope_kind" "inbox_v2_external_thread_scope_kind" NOT NULL,
	"alias_scope_source_connection_id" text,
	"alias_scope_source_account_id" text,
	"alias_scope_owner_key" text NOT NULL,
	"alias_object_kind_id" text NOT NULL,
	"alias_canonical_external_subject" text NOT NULL,
	"alias_key_digest" text GENERATED ALWAYS AS (encode(
    sha256(
      replace(
        'external-thread-key:v1|' ||
        octet_length("alias_realm_id")::text || ':' || "alias_realm_id" ||
        octet_length("alias_realm_version")::text || ':' || "alias_realm_version" ||
        octet_length("alias_canonicalization_version")::text || ':' || "alias_canonicalization_version" ||
        case "alias_scope_kind"
    when 'provider' then '8:provider'
    when 'source_connection' then '17:source_connection'
    when 'source_account' then '14:source_account'
  end ||
        case
      when "alias_scope_source_connection_id" is null then '-1:'
      else octet_length("alias_scope_source_connection_id")::text || ':' || "alias_scope_source_connection_id"
    end ||
        case
      when "alias_scope_source_account_id" is null then '-1:'
      else octet_length("alias_scope_source_account_id")::text || ':' || "alias_scope_source_account_id"
    end ||
        octet_length("alias_object_kind_id")::text || ':' || "alias_object_kind_id" ||
        octet_length("alias_canonical_external_subject")::text || ':' || "alias_canonical_external_subject",
        chr(92),
        chr(92) || chr(92)
