CREATE TABLE "inbox_v2_external_thread_key_registry" (
	"tenant_id" text NOT NULL,
	"id" text NOT NULL,
	"entry_kind" "inbox_v2_external_thread_key_kind" NOT NULL,
	"realm_id" text NOT NULL,
	"realm_version" text NOT NULL,
	"canonicalization_version" text NOT NULL,
	"scope_kind" "inbox_v2_external_thread_scope_kind" NOT NULL,
	"scope_source_connection_id" text,
	"scope_source_account_id" text,
	"scope_owner_key" text NOT NULL,
	"object_kind_id" text NOT NULL,
	"canonical_external_subject" text NOT NULL,
	"key_digest" text GENERATED ALWAYS AS (encode(
    sha256(
      replace(
        'external-thread-key:v1|' ||
        octet_length("realm_id")::text || ':' || "realm_id" ||
        octet_length("realm_version")::text || ':' || "realm_version" ||
        octet_length("canonicalization_version")::text || ':' || "canonicalization_version" ||
        case "scope_kind"
    when 'provider' then '8:provider'
    when 'source_connection' then '17:source_connection'
    when 'source_account' then '14:source_account'
  end ||
        case
      when "scope_source_connection_id" is null then '-1:'
      else octet_length("scope_source_connection_id")::text || ':' || "scope_source_connection_id"
    end ||
        case
      when "scope_source_account_id" is null then '-1:'
      else octet_length("scope_source_account_id")::text || ':' || "scope_source_account_id"
    end ||
        octet_length("object_kind_id")::text || ':' || "object_kind_id" ||
        octet_length("canonical_external_subject")::text || ':' || "canonical_external_subject",
        chr(92),
        chr(92) || chr(92)
      )::bytea
    ),
    'hex'
  )) STORED NOT NULL,
	"canonical_thread_id" text NOT NULL,
	"canonical_conversation_id" text NOT NULL,
	"revision" bigint DEFAULT 1 NOT NULL,
	"created_at" timestamp (3) with time zone DEFAULT now() NOT NULL,
	"updated_at" timestamp (3) with time zone DEFAULT now() NOT NULL,
	CONSTRAINT "inbox_v2_ext_thread_key_registry_pk" PRIMARY KEY("tenant_id","id"),
	CONSTRAINT "inbox_v2_ext_thread_key_digest_unique" UNIQUE("tenant_id","key_digest"),
	CONSTRAINT "inbox_v2_ext_thread_key_owner_unique" UNIQUE("tenant_id","id","entry_kind","canonical_thread_id","canonical_conversation_id","key_digest"),
	CONSTRAINT "inbox_v2_ext_thread_key_id_check" CHECK (char_length("inbox_v2_external_thread_key_registry"."id") <= 256
        and "inbox_v2_external_thread_key_registry"."id" ~ '^external_thread_key:[A-Za-z0-9][A-Za-z0-9._~:-]{0,199}$'),
	CONSTRAINT "inbox_v2_ext_thread_key_target_id_check" CHECK (char_length("inbox_v2_external_thread_key_registry"."canonical_thread_id") <= 256
        and "inbox_v2_external_thread_key_registry"."canonical_thread_id" ~ '^external_thread:[A-Za-z0-9][A-Za-z0-9._~:-]{0,199}$'),
	CONSTRAINT "inbox_v2_ext_thread_key_realm_check" CHECK (char_length("inbox_v2_external_thread_key_registry"."realm_id") <= 256 and (
        (
          "inbox_v2_external_thread_key_registry"."realm_id" ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'
          and char_length(split_part("inbox_v2_external_thread_key_registry"."realm_id", ':', 2)) <= 160
        ) or (
          "inbox_v2_external_thread_key_registry"."realm_id" ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'
          and char_length(split_part("inbox_v2_external_thread_key_registry"."realm_id", ':', 2)) <= 80
          and char_length(split_part("inbox_v2_external_thread_key_registry"."realm_id", ':', 3)) <= 160
          and split_part("inbox_v2_external_thread_key_registry"."realm_id", ':', 2) not in (
