	CONSTRAINT "inbox_v2_ext_thread_key_digest_check" CHECK ("inbox_v2_external_thread_key_registry"."key_digest" ~ '^[a-f0-9]{64}$'),
	CONSTRAINT "inbox_v2_ext_thread_key_immutable_check" CHECK ("inbox_v2_external_thread_key_registry"."revision" = 1
