CREATE TABLE "inbox_v2_source_account_identity_aliases" (
	"tenant_id" text NOT NULL,
	"id" text NOT NULL,
	"provisional_source_connection_id" text NOT NULL,
	"provisional_key_digest_sha256" text GENERATED ALWAYS AS (case
    when "provisional_source_connection_id" is null or "declaration_contract_id" is null or "declaration_contract_version" is null or "declaration_surface_id" is null or "provisional_connector_session_subject" is null then null
    else encode(
      sha256(
        replace(
          'source-account-provisional-key:v1|' ||
          octet_length("provisional_source_connection_id")::text || ':' || "provisional_source_connection_id" || octet_length("declaration_contract_id")::text || ':' || "declaration_contract_id" || octet_length("declaration_contract_version")::text || ':' || "declaration_contract_version" || octet_length("declaration_surface_id")::text || ':' || "declaration_surface_id" || octet_length("provisional_connector_session_subject")::text || ':' || "provisional_connector_session_subject",
          chr(92),
          chr(92) || chr(92)
        )::bytea
      ),
      'hex'
    )
  end) STORED NOT NULL,
	"provisional_connector_session_subject" text NOT NULL,
	"provisional_observed_at" timestamp (3) with time zone NOT NULL,
	"canonical_source_account_id" text NOT NULL,
	"canonical_key_digest_sha256" text GENERATED ALWAYS AS (case
    when "canonical_realm_id" is null or "canonical_realm_version" is null or "canonicalization_version" is null or "canonical_object_kind_id" is null or "canonical_scope_kind" is null or "canonical_external_subject" is null then null
    else encode(
      sha256(
        replace(
          'source-account-canonical-key:v1|' ||
          octet_length("canonical_realm_id")::text || ':' || "canonical_realm_id" || octet_length("canonical_realm_version")::text || ':' || "canonical_realm_version" || octet_length("canonicalization_version")::text || ':' || "canonicalization_version" || octet_length("canonical_object_kind_id")::text || ':' || "canonical_object_kind_id" || case "canonical_scope_kind"
    when 'provider' then '8:provider'
    when 'source_connection' then '17:source_connection'
  end || case
      when "canonical_scope_source_connection_id" is null then '-1:'
      else octet_length("canonical_scope_source_connection_id")::text || ':' || "canonical_scope_source_connection_id"
    end || octet_length("canonical_external_subject")::text || ':' || "canonical_external_subject",
          chr(92),
          chr(92) || chr(92)
        )::bytea
      ),
      'hex'
    )
  end) STORED NOT NULL,
	"canonical_realm_id" text NOT NULL,
	"canonical_realm_version" text NOT NULL,
	"canonicalization_version" text NOT NULL,
	"canonical_object_kind_id" text NOT NULL,
	"canonical_scope_kind" "inbox_v2_source_account_identity_scope_kind" NOT NULL,
	"canonical_scope_source_connection_id" text,
	"canonical_scope_owner_key" text NOT NULL,
	"canonical_external_subject" text NOT NULL,
	"identity_declaration" jsonb NOT NULL,
	"declaration_contract_id" text NOT NULL,
	"declaration_contract_version" text NOT NULL,
	"declaration_revision" bigint NOT NULL,
	"declaration_surface_id" text NOT NULL,
	"declaration_loaded_by_trusted_service_id" text NOT NULL,
	"declaration_loaded_at" timestamp (3) with time zone NOT NULL,
	"declaration_realm_id" text NOT NULL,
	"declaration_realm_version" text NOT NULL,
	"declaration_canonicalization_version" text NOT NULL,
	"declaration_object_kind_id" text NOT NULL,
	"declaration_scope_kind" "inbox_v2_source_account_identity_scope_kind" NOT NULL,
	"expected_account_identity_revision" bigint NOT NULL,
	"expected_account_generation" bigint NOT NULL,
	"target_identity_state" "inbox_v2_source_account_identity_state" NOT NULL,
	"decision_actor_trusted_service_id" text NOT NULL,
	"decision_policy_id" text NOT NULL,
	"decision_policy_version" text NOT NULL,
	"decision_reason_code_id" text NOT NULL,
	"decision_verification_evidence_token" text NOT NULL,
	"decision_decided_at" timestamp (3) with time zone NOT NULL,
	"revision" bigint NOT NULL,
	"created_at" timestamp (3) with time zone NOT NULL,
	CONSTRAINT "inbox_v2_source_account_identity_aliases_pk" PRIMARY KEY("tenant_id","id"),
	CONSTRAINT "inbox_v2_account_identity_aliases_provisional_key_unique" UNIQUE("tenant_id","provisional_key_digest_sha256"),
	CONSTRAINT "inbox_v2_account_identity_aliases_target_edge_unique" UNIQUE("tenant_id","id","canonical_source_account_id","expected_account_identity_revision","expected_account_generation","target_identity_state","canonical_key_digest_sha256"),
	CONSTRAINT "inbox_v2_source_account_identity_aliases_id_check" CHECK (char_length("inbox_v2_source_account_identity_aliases"."id") <= 256
        and "inbox_v2_source_account_identity_aliases"."id" ~ '^source_account_identity_alias:[A-Za-z0-9][A-Za-z0-9._~:-]{0,199}$'),
	CONSTRAINT "inbox_v2_account_identity_aliases_declaration_check" CHECK (jsonb_typeof("inbox_v2_source_account_identity_aliases"."identity_declaration") = 'object'
    and pg_column_size("inbox_v2_source_account_identity_aliases"."identity_declaration") <= 16384
    and "inbox_v2_source_account_identity_aliases"."identity_declaration" = jsonb_build_object(
      'adapterContract', jsonb_build_object(
        'contractId', "inbox_v2_source_account_identity_aliases"."declaration_contract_id",
        'contractVersion', "inbox_v2_source_account_identity_aliases"."declaration_contract_version",
        'declarationRevision', "inbox_v2_source_account_identity_aliases"."declaration_revision"::text,
