        'loadedByTrustedServiceId', "inbox_v2_source_account_identity_aliases"."declaration_loaded_by_trusted_service_id",
        'loadedAt', "inbox_v2_source_account_identity_aliases"."identity_declaration" #>> '{adapterContract,loadedAt}'
      ),
      'identityKind', 'source_account',
      'realmId', "inbox_v2_source_account_identity_aliases"."declaration_realm_id",
      'realmVersion', "inbox_v2_source_account_identity_aliases"."declaration_realm_version",
      'canonicalizationVersion', "inbox_v2_source_account_identity_aliases"."declaration_canonicalization_version",
      'objectKindId', "inbox_v2_source_account_identity_aliases"."declaration_object_kind_id",
      'scopeKind', "inbox_v2_source_account_identity_aliases"."declaration_scope_kind"::text,
