    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.conversation_id, old.conversation_id)
  );
  perform public.inbox_v2_assert_conversation_membership_projection(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.conversation_id, old.conversation_id)
  );
  return null;
end;
$function$;

